# v1 scanner, comp/clear, loss policy
base = base.replace('NST     equ 3', 'NST     equ 2')
base = base.replace('strat0  jmp comp\nstrat1  jmp clear\nstrat2  jmp dwarf\n', 'strat0  jmp comp\nstrat1  jmp clear\n')
