def make_clear(ptr, count, bomb, mode='>'):
    return f'''cptr    dat #0,#{ptr}\ncbomb   {bomb}\nclear   spl 0\n        mov cbomb,{mode}cptr\n        djn -1,#{count}\n        end\n'''

